public boolean hasAttr(String attributeName) {
    Validate.notEmpty(attributeName);

    if(attributeName.startsWith("xml:")){
        String key = attributeName.replaceFirst("xml:","");
        return hasAttribute(key);
    }else{
        Attributes attributes=this.attributes;
        int index=attributeName.indexOf(':');
        if(index>0&&attributeName.length()>1){
            String uri = attributeName.substring(0, index);
            String localName = attributeName.substring(index + 1);
            NamedNodeMap nnm = attributes();

            for (int i = 0; i < nnm.getLength(); i++) {
                Attr attr=nnm.item(i);

                if ((Utils.isBlank(uri) && attr.getName().equals(localName))||
                    (!Utils.isBlank(uri) && 
                     (attr.getName().endsWith(uri + ":"+ localName))) ){
                    return true;
                }
            }
        } else {
           return this.attributes != null && this.attributes.getNamedItem(attributeName)!=null;
        }

    }
   return false;
}

